import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.create
import java.util.concurrent.TimeUnit

object NetworkingModule {

    private const val BASE_URL_DEV = "https://api.example.com/"
    private const val BASE_URL_STAGING = "https://api.example.com/"
    private const val BASE_URL_PRODUCTION = "https://api.example.com/"

    private var retrofit: Retrofit? = null

    val userApi: UserApi
        get() = retrofit?.create() ?: buildRetrofit().create()

    private fun buildRetrofit(): Retrofit {
        retrofit = Retrofit.Builder()
            .baseUrl(getBaseUrl())
            .addConverterFactory(GsonConverterFactory.create())
            .client(getOkHttpClient())
            .build()

        return retrofit!!
    }

    private fun getBaseUrl(): String {
        return when (BuildConfig.BUILD_TYPE) {
            "debug" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            else -> BASE_URL_PRODUCTION
        }
    }

    private fun getOkHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor())
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()
    }
}

interface UserApi {
    @GET("users")
    suspend fun fetchProfiles(): List<UserProfile>
}

data class UserProfile(val id: Int, val name: String)

class AuthInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request().newBuilder()
            .addHeader("Authorization", "Bearer ${BuildConfig.API_TOKEN}")
            .build()
        return chain.proceed(request)
    }
}